const mailbox = ctx.getLabel({ model_id: -1, p: 0, r: 0, c: 1, k: 'ui_event' });
console.log('[forward_ui_events] mailbox value:', JSON.stringify(mailbox));
if (mailbox) {
  var payload = mailbox.payload || mailbox;
  var action = payload.action || 'unknown';
  var meta = payload && payload.meta && typeof payload.meta === 'object' ? payload.meta : {};
  var opId = meta.op_id || ('ui_' + Date.now());
  if (meta.local_only === true || (typeof action === 'string' && action.indexOf('llm_filltable_') === 0)) {
    console.log('[forward_ui_events] Skipping local-only action:', action);
    return;
  }
  var targetModelId = null;
  if (Number.isInteger(meta.model_id)) {
    targetModelId = meta.model_id;
  } else if (payload.target && Number.isInteger(payload.target.model_id)) {
    targetModelId = payload.target.model_id;
  }

  // Only forward app-level events (positive model ids). Editor state/routing must not leak to Matrix.
  if (targetModelId === null || targetModelId <= 0) {
    console.log('[forward_ui_events] Skipping - non-app target model', targetModelId);
    return;
  }

  var dbCheck = ctx.getLabel({ model_id: targetModelId, p: 0, r: 0, c: 0, k: 'dual_bus_model' });
  if (dbCheck) {
    console.log('[forward_ui_events] Skipping - dual_bus_model forwarder handles model', targetModelId);
    return;
  }

  console.log('[forward_ui_events] Forwarding to Matrix:', action, 'op_id:', opId);
  var p = ctx.sendMatrix({
    version: 'v0',
    type: 'ui_event',
    op_id: opId,
    action: action,
    data: payload,
    timestamp: Date.now()
  });
  if (p && typeof p.then === 'function') {
    p.then(function() { console.log('[forward_ui_events] Matrix send OK'); })
     .catch(function(err) { console.warn('[forward_ui_events] Matrix send failed (non-fatal):', err.message); });
  } else if (!p) {
    console.warn('[forward_ui_events] Matrix not available, skipping forward');
  }
} else {
  console.log('[forward_ui_events] No mailbox data, skipping');
}
